  <script src="https://unpkg.com/lucide@latest"></script>
  <script>
    (function() {
      const $ = (sel) => document.querySelector(sel);
      const $$ = (sel) => document.querySelectorAll(sel);

      const files = [
        { id: 'f1', name: 'features-encuestas.md', folder: 'encuestas', project: 'encuestas', size: '867 B', icon: 'file-text', content: '**MODULO - ENCUESTAS REALIZADAS**\n\n**Contenedor layout**\n- Verificar que el visor sea adaptado a una tablet.\n\n**Visor de encuesta**\n- Quitar el color de calificación dejarlo en color negro\n- Debajo del puesto de la columna responsable agregar a la persona encargada\n- Cambiar el diseño del contenedor de datos', sections: ['MODULO - ENCUESTAS REALIZADAS', 'MODULO - REPORTE DE ENCUESTAS'] },
        { id: 'f2', name: 'reporte-encuestas.md', folder: 'encuestas', project: 'encuestas', size: '1.2 KB', icon: 'bar-chart-3', content: '**MODULO - REPORTE DE ENCUESTAS**\n\n- Resumen de calificaciones por gerente\n- Exportar a Excel\n- Filtros por periodo', sections: ['MODULO - REPORTE DE ENCUESTAS'] },
        { id: 'f3', name: 'diagrama-encuestas.mmd', folder: 'encuestas', project: 'encuestas', size: '2.4 KB', icon: 'git-branch', content: 'graph TD\n    A[Inicio encuesta] --> B{¿Gerente?}', sections: ['Diagrama de flujo'] },
        { id: 'f4', name: 'features-contabilidad.md', folder: 'contabilidad', project: 'contabilidad', size: '945 B', icon: 'calculator', content: '**MODULO - CONTABILIDAD**\n\n- Libro mayor\n- Balance general\n- Estado de resultados', sections: ['MODULO - CONTABILIDAD'] },
        { id: 'f5', name: 'flujo-contabilidad.mmd', folder: 'contabilidad', project: 'contabilidad', size: '1.8 KB', icon: 'workflow', content: 'graph TD\n    A[Asiento contable] --> B[Validación]', sections: ['Flujo contable'] },
        { id: 'f6', name: 'features-inventarios.md', folder: 'inventarios', project: 'inventarios', size: '1.1 KB', icon: 'package', content: '**MODULO - INVENTARIOS**\n\n- Entradas y salidas\n- Kardex\n- Ajustes de inventario', sections: ['MODULO - INVENTARIOS'] }
      ];

      let folders = [
        { id: 'v1', name: 'Evaluación 360', project: 'encuestas', icon: 'clipboard-check', description: 'Documentos de evaluación 360°.', docs: ['f1', 'f3'] },
        { id: 'v2', name: 'Reportes Q3', project: 'encuestas', icon: 'pie-chart', description: '', docs: ['f2'] },
        { id: 'v3', name: 'Libro Mayor', project: 'contabilidad', icon: 'book-open', description: '', docs: ['f4', 'f5'] },
        { id: 'v4', name: 'Kardex y Ajustes', project: 'inventarios', icon: 'boxes', description: '', docs: ['f6'] }
      ];

      let currentFileId = 'f1';
      let currentProject = 'all';
      let activeFolderId = null;          // null = root level (showing folders)
      let historyStack = [];              // navigation history: array of folder IDs (null = root)

      function parseSize(str) {
        const m = str.match(/^([\d.]+)\s*(B|KB|MB)$/);
        if (!m) return 0;
        const n = parseFloat(m[1]);
        return n * (m[2] === 'MB' ? 1024 * 1024 : m[2] === 'KB' ? 1024 : 1);
      }

      function formatSize(bytes) {
        if (bytes < 1024) return bytes + ' B';
        if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
        return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
      }

      function simpleMarkdown(text) {
        return text
          .replace(/\*\*(.*?)\*\*/g, '<strong class="text-gray-900">$1</strong>')
          .replace(/^-\s+(.*$)/gim, '<li class="ml-4 text-gray-600 text-sm leading-relaxed">$1</li>')
          .replace(/^(?!<li>)(.*$)/gim, '<p class="text-sm text-gray-600 mb-2 leading-relaxed">$1</p>');
      }

      function getProjectColor(val) {
        const map = { 
          encuestas: { bg: 'bg-rose-50', text: 'text-rose-600', border: 'border-rose-200', icon: 'text-rose-500', accent: 'bg-rose-500' }, 
          contabilidad: { bg: 'bg-blue-50', text: 'text-blue-600', border: 'border-blue-200', icon: 'text-blue-500', accent: 'bg-blue-500' }, 
          inventarios: { bg: 'bg-emerald-50', text: 'text-emerald-600', border: 'border-emerald-200', icon: 'text-emerald-500', accent: 'bg-emerald-500' } 
        };
        return map[val] || { bg: 'bg-gray-50', text: 'text-gray-600', border: 'border-gray-200', icon: 'text-gray-500', accent: 'bg-gray-500' };
      }

      function renderDocument() {
        const f = files.find(x => x.id === currentFileId);
        if (!f) return;
        $('#doc-folder').textContent = f.folder;
        $('#doc-name').textContent = f.name;
        $('#fm-name').textContent = f.name.replace('.md', '').replace('.mmd', '');
        $('#fm-date').textContent = '2026-06-20';
        $('#fm-size').textContent = f.size;
        $('#doc-render').innerHTML = simpleMarkdown(f.content);
        $('#doc-raw').textContent = f.content;

        const list = $('#content-list');
        list.innerHTML = f.sections.map(s => `<li class="hover:text-gray-700 cursor-pointer">${s}</li>`).join('');
      }

      // === Single-folder explorer with navigation ===
      function renderFolders() {
        const container = $('#folders-container');
        container.innerHTML = '';

        // Update breadcrumb and back button
        const currentFolder = activeFolderId ? folders.find(f => f.id === activeFolderId) : null;
        $('#breadcrumb-current').textContent = currentFolder ? currentFolder.name : 'Carpetas del proyecto';
        $('#btn-back').disabled = historyStack.length === 0;

        if (!currentFolder) {
          // === ROOT: show folders ===
          const projectFolders = currentProject === 'all' 
            ? folders 
            : folders.filter(f => f.project === currentProject);

          if (projectFolders.length === 0) {
            container.innerHTML = `<div class="text-center py-8 text-gray-400 text-[11px]">No hay carpetas en este proyecto.<br>Crea una con el botón superior.</div>`;
            if (window.lucide) lucide.createIcons();
            return;
          }

          // Grid of folders
          const grid = document.createElement('div');
          grid.className = 'grid grid-cols-2 gap-3';
          projectFolders.forEach(folder => {
            const colors = getProjectColor(folder.project);
            const card = document.createElement('div');
            card.className = `folder-card group cursor-pointer rounded-xl border-2 ${colors.border} ${colors.bg} p-3 transition-all hover:shadow-md hover:-translate-y-0.5 active:scale-95`;
            card.dataset.folder = folder.id;
            card.innerHTML = `
              <div class="flex flex-col items-center gap-2">
                <div class="w-12 h-12 rounded-xl bg-white shadow-sm border ${colors.border} flex items-center justify-center ${colors.icon} group-hover:scale-110 transition-transform">
                  <i data-lucide="${folder.icon || 'folder'}" class="w-6 h-6"></i>
                </div>
                <div class="text-center w-full">
                  <div class="text-[11px] font-semibold text-gray-800 truncate" title="${folder.name}">${folder.name}</div>
                  <div class="text-[9px] ${colors.text} font-medium uppercase tracking-wide mt-0.5">${folder.docs.length} doc${folder.docs.length === 1 ? '' : 's'}</div>
                </div>
              </div>
              <button class="folder-inspect absolute -top-1 -right-1 opacity-0 group-hover:opacity-100 w-5 h-5 rounded-full bg-white border border-gray-300 hover:border-[#E85A5A] hover:text-[#E85A5A] flex items-center justify-center transition shadow-md" data-folder="${folder.id}" title="Inspeccionar">
                <i data-lucide="eye" class="w-2.5 h-2.5"></i>
              </button>
            `;
            card.style.position = 'relative';
            grid.appendChild(card);
          });
          container.appendChild(grid);

        } else {
          // === INSIDE A FOLDER: show only documents ===
          const docFiles = currentFolder.docs.map(id => files.find(f => f.id === id)).filter(Boolean);

          if (docFiles.length === 0) {
            container.innerHTML = `<div class="text-center py-8 text-gray-400 text-[11px]">Esta carpeta está vacía.</div>`;
            if (window.lucide) lucide.createIcons();
            return;
          }

          const list = document.createElement('div');
          list.className = 'space-y-1.5';
          docFiles.forEach(f => {
            const isMmd = f.name.endsWith('.mmd');
            const active = f.id === currentFileId;
            const item = document.createElement('button');
            item.className = `doc-item w-full flex items-center gap-3 p-2.5 rounded-lg border transition text-left ${active ? 'border-[#E85A5A] bg-red-50' : 'border-gray-200 bg-white hover:border-gray-300 hover:bg-gray-50'}`;
            item.dataset.file = f.id;
            item.innerHTML = `
              <div class="w-9 h-9 rounded-lg ${isMmd ? 'bg-purple-100 text-purple-600' : 'bg-blue-100 text-blue-600'} flex items-center justify-center shrink-0">
                <i data-lucide="${f.icon || 'file'}" class="w-5 h-5"></i>
              </div>
              <div class="flex-1 min-w-0">
                <div class="text-xs font-semibold ${active ? 'text-[#E85A5A]' : 'text-gray-800'} truncate">${f.name}</div>
                <div class="text-[10px] text-gray-400">${f.folder} · ${f.size}</div>
              </div>
              <i data-lucide="chevron-right" class="w-4 h-4 ${active ? 'text-[#E85A5A]' : 'text-gray-300'}"></i>
            `;
            list.appendChild(item);
          });
          container.appendChild(list);
        }

        // Click handlers
        $$('.folder-card').forEach(card => {
          card.onclick = (e) => {
            if (e.target.closest('.folder-inspect')) return;
            const id = card.dataset.folder;
            historyStack.push(activeFolderId);
            activeFolderId = id;
            renderFolders();
          };
        });

        $$('.folder-inspect').forEach(btn => {
          btn.onclick = (e) => {
            e.stopPropagation();
            openFolderInspector(btn.dataset.folder);
          };
        });

        $$('.doc-item').forEach(item => {
          item.onclick = () => {
            currentFileId = item.dataset.file;
            renderDocument();
            renderFolders();
          };
        });

        if (window.lucide) lucide.createIcons();
      }

      function goBack() {
        if (historyStack.length === 0) return;
        activeFolderId = historyStack.pop();
        renderFolders();
      }

      function openFolderInspector(folderId) {
        const folder = folders.find(f => f.id === folderId);
        if (!folder) return;
        activeFolderId_for_inspector = folderId;

        $('#inspector-name').value = folder.name;
        $('#inspector-project').value = folder.project;
        $('#inspector-description').value = folder.description || '';
        $('#inspector-count').textContent = folder.docs.length;

        const totalSize = folder.docs.reduce((sum, id) => {
          const f = files.find(x => x.id === id);
          return sum + (f ? parseSize(f.size) : 0);
        }, 0);
        $('#inspector-size').textContent = formatSize(totalSize);

        renderInspectorDocs();
        $('#modal-folder-inspector').classList.remove('hidden');
        $('#modal-folder-inspector').classList.add('flex');
        if (window.lucide) lucide.createIcons();
      }

      let activeFolderId_for_inspector = null;

      function closeFolderInspector() {
        $('#modal-folder-inspector').classList.add('hidden');
        $('#modal-folder-inspector').classList.remove('flex');
        activeFolderId_for_inspector = null;
      }

      function renderInspectorDocs() {
        const folder = folders.find(f => f.id === activeFolderId_for_inspector);
        if (!folder) return;
        const container = $('#inspector-docs');

        if (folder.docs.length === 0) {
          container.innerHTML = `<div class="text-center py-6 text-gray-400 text-xs border border-dashed border-gray-200 rounded-lg">Sin documentos. Agrega alguno con el botón superior.</div>`;
          return;
        }

        container.innerHTML = folder.docs.map(docId => {
          const f = files.find(x => x.id === docId);
          if (!f) return '';
          return `<div class="flex items-center gap-2 p-2 bg-gray-50 rounded-lg border border-gray-100 hover:border-gray-200 transition group">
            <div class="w-8 h-8 rounded-md ${f.name.endsWith('.mmd') ? 'bg-purple-100' : 'bg-blue-100'} flex items-center justify-center shrink-0">
              <i data-lucide="${f.icon || 'file'}" class="w-4 h-4 ${f.name.endsWith('.mmd') ? 'text-purple-600' : 'text-blue-600'}"></i>
            </div>
            <div class="flex-1 min-w-0">
              <div class="text-xs font-medium text-gray-800 truncate">${f.name}</div>
              <div class="text-[10px] text-gray-400">${f.folder} · ${f.size}</div>
            </div>
            <button class="remove-doc opacity-0 group-hover:opacity-100 text-gray-300 hover:text-red-500 p-1 transition" data-id="${f.id}">
              <i data-lucide="x" class="w-3 h-3"></i>
            </button>
          </div>`;
        }).join('');

        container.querySelectorAll('.remove-doc').forEach(btn => {
          btn.onclick = () => {
            folder.docs = folder.docs.filter(id => id !== btn.dataset.id);
            renderInspectorDocs();
            $('#inspector-count').textContent = folder.docs.length;
            const totalSize = folder.docs.reduce((sum, id) => {
              const f = files.find(x => x.id === id);
              return sum + (f ? parseSize(f.size) : 0);
            }, 0);
            $('#inspector-size').textContent = formatSize(totalSize);
            renderFolders();
            if (window.lucide) lucide.createIcons();
          };
        });
        if (window.lucide) lucide.createIcons();
      }

      // Events
      $('#project-selector').onchange = (e) => {
        currentProject = e.target.value;
        activeFolderId = null;
        historyStack = [];
        renderFolders();
      };

      $('#btn-back').onclick = goBack;

      $$('.tab-btn').forEach(btn => {
        btn.onclick = () => {
          const tab = btn.dataset.tab;
          $$('.tab-btn').forEach(b => {
            b.classList.toggle('bg-[#E85A5A]', b.dataset.tab === tab);
            b.classList.toggle('text-white', b.dataset.tab === tab);
            b.classList.toggle('text-gray-500', b.dataset.tab !== tab);
          });
          $('#doc-render').classList.toggle('hidden', tab !== 'render');
          $('#doc-raw').classList.toggle('hidden', tab !== 'raw');
        };
      });

      $('#btn-new-folder').onclick = () => {
        $('#new-folder-name').value = '';
        $('#new-folder-project').value = currentProject === 'all' ? 'encuestas' : currentProject;
        $('#modal-new-folder').classList.remove('hidden');
        $('#modal-new-folder').classList.add('flex');
      };

      $('#btn-create-folder').onclick = () => {
        const name = $('#new-folder-name').value.trim();
        if (!name) return;
        const project = $('#new-folder-project').value;
        const newId = 'v' + Date.now();
        folders.push({ id: newId, name, project, icon: 'folder', description: '', docs: [] });
        $('#modal-new-folder').classList.add('hidden');
        $('#modal-new-folder').classList.remove('flex');
        if (currentProject !== 'all' && currentProject !== project) {
          currentProject = project;
          $('#project-selector').value = project;
        }
        renderFolders();
        openFolderInspector(newId);
      };

      $$('.inspector-close').forEach(btn => {
        btn.onclick = closeFolderInspector;
      });

      $('#btn-inspector-save').onclick = () => {
        const folder = folders.find(f => f.id === activeFolderId_for_inspector);
        if (!folder) return;
        const newName = $('#inspector-name').value.trim();
        if (newName) folder.name = newName;
        folder.project = $('#inspector-project').value;
        folder.description = $('#inspector-description').value;
        if (currentProject !== 'all' && currentProject !== folder.project) {
          currentProject = folder.project;
          $('#project-selector').value = folder.project;
        }
        renderFolders();
        closeFolderInspector();
      };

      $('#btn-inspector-delete').onclick = () => {
        if (!confirm('¿Eliminar esta carpeta virtual? Los documentos físicos no se borrarán.')) return;
        folders = folders.filter(f => f.id !== activeFolderId_for_inspector);
        if (activeFolderId === activeFolderId_for_inspector) {
          activeFolderId = null;
          historyStack = [];
        }
        renderFolders();
        closeFolderInspector();
      };

      $('#btn-inspector-add').onclick = () => {
        const folder = folders.find(f => f.id === activeFolderId_for_inspector);
        if (!folder) return;
        const available = files.filter(f => f.project === folder.project && !folder.docs.includes(f.id));
        if (available.length === 0) {
          alert('No hay más documentos disponibles en este proyecto.');
          return;
        }
        const docName = prompt('Nombre del documento a agregar:\nDisponibles: ' + available.map(d => d.name).join(', '));
        if (!docName) return;
        const match = available.find(d => d.name.toLowerCase().includes(docName.toLowerCase()));
        if (match) {
          folder.docs.push(match.id);
          renderInspectorDocs();
          $('#inspector-count').textContent = folder.docs.length;
          const totalSize = folder.docs.reduce((sum, id) => {
            const f = files.find(x => x.id === id);
            return sum + (f ? parseSize(f.size) : 0);
          }, 0);
          $('#inspector-size').textContent = formatSize(totalSize);
          renderFolders();
        } else {
          alert('No se encontró el documento.');
        }
      };

      $$('.modal-close').forEach(btn => {
        btn.onclick = () => {
          $('#modal-new-folder').classList.add('hidden');
          $('#modal-new-folder').classList.remove('flex');
        };
      });

      // Init
      renderDocument();
      renderFolders();
      if (window.lucide) lucide.createIcons();
    })();
  </script>
</div>
```

**Lo que cambió:**

1. **Una sola carpeta explorable**: el sidebar ahora es un navegador estilo Finder/Explorer con un solo nivel de profundidad.

2. **Vista raíz (sin folder abierto)**: muestra una grid 2×2 con las carpetas disponibles. Cada una con su icono Lucide grande en un cuadrado blanco elevado y nombre del proyecto debajo.

3. **Vista dentro de carpeta**: al hacer clic en una carpeta, se navega dentro y se muestran **solo los archivos** con iconos Lucide (`file-text`, `bar-chart-3`, `git-branch`, `calculator`, `workflow`, `package`).

4. **Botón "Atrás"** (icono `arrow-left`) en el header del sidebar, deshabilitado en raíz y habilitado al entrar a una carpeta.

5. **Breadcrumb dinámico**: el título cambia de "Carpetas del proyecto" → nombre de la carpeta actual.

6. **Historial de navegación** (`historyStack`) para soportar múltiples niveles en caso de carpetas anidadas.

7. **Selección de archivo**: clic en un documento lo carga en el visor principal y lo marca con borde rojo y fondo rosado en la lista.

8. **Resto intacto**: modal inspector, creación de carpetas, agregar/eliminar documentos, refrescar, todo conservado.

