        <!-- Finder Header -->
        <div class="flex items-center justify-between px-3 py-2 border-b border-gray-200 bg-gray-50">
          <div class="flex items-center gap-1.5">
            <button id="btn-back" class="w-7 h-7 rounded-md flex items-center justify-center text-gray-500 hover:bg-gray-200 transition disabled:opacity-30 disabled:cursor-not-allowed" disabled title="Atrás">
              <i data-lucide="chevron-left" class="w-4 h-4"></i>
