          <button id="btn-new-folder" class="w-7 h-7 rounded-md flex items-center justify-center bg-[#E85A5A] text-white hover:bg-[#D44A4A] transition shadow-sm" title="Nueva carpeta">
            <i data-lucide="folder-plus" class="w-3.5 h-3.5"></i>
