        <div class="h-11 bg-white border-b border-gray-200 flex items-center justify-between px-4">
          <div class="flex items-center gap-2 text-xs text-gray-500">
            <span>documents</span><span>/</span><span id="doc-folder">encuestas</span><span>/</span><span id="doc-name" class="text-gray-800 font-medium">features-encuestas.md</span>
          </div>
          <div class="flex items-center gap-1 bg-gray-100 rounded-lg p-0.5">
            <button class="tab-btn px-3 py-1 rounded-md text-xs font-medium bg-[#E85A5A] text-white" data-tab="render">Renderizado</button>
            <button class="tab-btn px-3 py-1 rounded-md text-xs font-medium text-gray-500 hover:text-gray-700" data-tab="raw">Raw</button>
          </div>
        </div>
        <div class="flex-1 overflow-y-auto p-5">
          <div class="max-w-3xl mx-auto bg-white rounded-xl border border-gray-200 shadow-sm p-8">
            <div id="doc-render" class="prose prose-sm max-w-none"></div>
            <pre id="doc-raw" class="hidden text-xs font-mono text-gray-600 whitespace-pre-wrap"></pre>
          </div>
        </div>
      </div>
