  </div>

  <!-- Modal: New Folder -->
  <div id="modal-new-folder" class="fixed inset-0 bg-black/40 hidden items-center justify-center z-40">
    <div class="bg-white rounded-xl shadow-xl w-full max-w-sm mx-4 overflow-hidden">
      <div class="px-4 py-3 border-b border-gray-200 flex justify-between items-center">
        <h3 class="text-sm font-semibold text-gray-800">Nueva carpeta virtual</h3>
        <button class="modal-close text-gray-400 hover:text-gray-600 text-lg leading-none">&times;</button>
      </div>
      <div class="p-4 space-y-3">
        <div>
          <label class="block text-[11px] font-medium text-gray-500 uppercase mb-1">Nombre</label>
          <input id="new-folder-name" type="text" class="w-full h-9 px-3 rounded-lg border border-gray-200 text-sm focus:outline-none focus:border-[#E85A5A]" placeholder="Ej: Evaluación 360">
        </div>
        <div>
          <label class="block text-[11px] font-medium text-gray-500 uppercase mb-1">Proyecto</label>
          <select id="new-folder-project" class="w-full h-9 px-3 rounded-lg border border-gray-200 text-sm bg-white focus:outline-none focus:border-[#E85A5A]">
            <option value="encuestas">Encuestas</option>
            <option value="contabilidad">Contabilidad</option>
            <option value="inventarios">Inventarios</option>
          </select>
