      <div class="px-4 py-3 border-t border-gray-200 bg-gray-50 flex justify-end gap-2">
        <button class="modal-close h-8 px-3 rounded-lg text-xs font-medium text-gray-600 hover:bg-gray-100">Cancelar</button>
        <button id="btn-create-folder" class="h-8 px-3 rounded-lg bg-[#E85A5A] text-white text-xs font-medium hover:bg-[#D44A4A]">Crear</button>
      </div>
    </div>
