  <!-- Folder Inspector Modal -->
  <div id="modal-folder-inspector" class="fixed inset-0 bg-black/40 hidden items-center justify-center z-40">
    <div class="bg-white rounded-xl shadow-2xl w-full max-w-2xl mx-4 max-h-[90vh] overflow-hidden flex flex-col">
      <div class="relative h-24 bg-gradient-to-br from-[#E85A5A] to-[#D44A4A] flex items-end px-5 pb-3">
        <button class="inspector-close absolute top-3 right-3 text-white/80 hover:text-white">
          <i data-lucide="x" class="w-5 h-5"></i>
        </button>
        <div class="flex items-center gap-3 text-white">
          <div class="w-12 h-12 rounded-xl bg-white/20 backdrop-blur flex items-center justify-center">
            <i data-lucide="folder-open" class="w-6 h-6"></i>
          </div>
          <div>
            <div class="text-[10px] uppercase tracking-wider text-white/70 font-medium">Carpeta virtual</div>
            <input id="inspector-name" type="text" class="text-lg font-bold bg-transparent border-b border-transparent hover:border-white/30 focus:border-white focus:outline-none w-full mt-0.5">
          </div>
        </div>
