      function formatSize(b) { if (b < 1024) return b + ' B'; if (b < 1024 * 1024) return (b / 1024).toFixed(1) + ' KB'; return (b / (1024 * 1024)).toFixed(1) + ' MB'; }
      function simpleMarkdown(t) { return t.replace(/\*\*(.*?)\*\*/g, '<strong class="text-gray-900">$1</strong>').replace(/^-\s+(.*$)/gim, '<li class="ml-4 text-gray-600 text-sm leading-relaxed">$1</li>').replace(/^(?!<li>)(.*$)/gim, '<p class="text-sm text-gray-600 mb-2 leading-relaxed">$1</p>'); }
