          const projectFolders = currentProject === 'all' ? folders : folders.filter(f => f.project === currentProject);

          // Get files that are NOT inside any folder
          const allFolderDocIds = folders.flatMap(f => f.docs);
          const looseFiles = files.filter(f => (currentProject === 'all' || f.project === currentProject) && !allFolderDocIds.includes(f.id));

          // Combine and map to generic items
          items = [
            ...projectFolders.map(f => ({ ...f, type: 'folder' })),
            ...looseFiles.map(f => ({ ...f, type: 'file' }))
          ];
        } else {
          // INSIDE FOLDER: Only files
          items = currentFolder.docs.map(id => {
            const f = files.find(x => x.id === id);
            return f ? { ...f, type: 'file' } : null;
          }).filter(Boolean);
        }

        if (items.length === 0) {
          container.innerHTML = `<div class="col-span-full text-center py-12 text-gray-400 text-xs">Carpeta vacía.</div>`;
          if (window.lucide) lucide.createIcons();
          return;
